function base64ToBytes(base64: string): Uint8Array {
  if (typeof Buffer !== 'undefined') {
    return Uint8Array.from(Buffer.from(base64, 'base64'));
  }
  if (typeof atob !== 'function') return new Uint8Array();
  const binary = atob(base64);
  const out = new Uint8Array(binary.length);
  for (let i = 0; i < binary.length; i += 1) out[i] = binary.charCodeAt(i);
  return out;
}

function normalize(desc: unknown): string {
  if (typeof desc !== 'string') return 'UNKNOWN';

  return desc
    .toUpperCase()
    .trim()
    .replace(/[.,]/g, ' ')
    .replace(/\bTRXN\b/g, 'TRANSACTION')
    .replace(/\bAMT\b/g, 'AMOUNT')
    .replace(/\bCNT\b/g, 'COUNT')
    .replace(/\bLMT\b/g, 'LIMIT')
    .replace(/\bACCT\b/g, 'ACCOUNT')
    .replace(/\s*\/\s*/g, '/')
    .replace(/\s+/g, ' ')
    .trim() || 'UNKNOWN';
}

