function getChannelCauseMap(reportType?: string): Record<string, string> {
  const channel = normalize(reportType || '');
  if (channel.includes('ATM')) return ATM_CAUSE_MAP;
  if (channel.includes('IPG')) return IPG_CAUSE_MAP;
  if (channel.includes('POS')) return POS_CAUSE_MAP;
  return POS_CAUSE_MAP;
}

type DeclineLike = { description?: string | null; volume?: number | null; typicalCause?: string };

function buildTopDeclinesByDescription(failures: DeclineLike[], causeMap: Record<string, string>) {
  const grouped = new Map<string, number>();

  for (const failure of failures || []) {
    const raw = typeof failure?.description === 'string' ? failure.description : '';
    const description = raw.trim() || 'UNKNOWN';
    const volume = Number(failure?.volume ?? 0);
    if (!Number.isFinite(volume) || volume <= 0) continue;
    grouped.set(description, (grouped.get(description) ?? 0) + volume);
  }

  return [...grouped.entries()]
    .sort((a, b) => b[1] - a[1])
    .slice(0, 15)
    .map(([description, volume]) => {
      const key = normalize(description);
      return {
        description,
        volume,
        typicalCause: causeMap[key] ?? DEFAULT_TYPICAL_CAUSE
      };
    });
}

function buildHeaderCell(text: string) {
  return new TableCell({
    children: [new Paragraph({ children: [new TextRun({ text, bold: true, font: DEFAULT_FONT, size: DEFAULT_SIZE })] })]
  });
}

function buildCell(text: string) {
  return new TableCell({
    children: [new Paragraph({ children: [new TextRun({ text, font: DEFAULT_FONT, size: DEFAULT_SIZE })] })]
  });
}

function derivePeriodLabel(startDateIso?: string, endDateIso?: string, fallback?: string) {
  const start = startDateIso ? new Date(startDateIso) : null;
  const end = endDateIso ? new Date(endDateIso) : null;
  if (start && end && !isNaN(start.getTime()) && !isNaN(end.getTime())) {
    if (start.getFullYear() === end.getFullYear() && start.getMonth() === end.getMonth()) {
      return start.toLocaleString('en-US', { month: 'short' });
    }
  }
  return fallback || 'N/A';
}

function buildCentralBankDocument(data: ReportData): Document {
  let businessFailures = (data.businessFailures || [])
    .filter((f) => (f.volume ?? 0) > 0)
    .sort((a, b) => (b.volume ?? 0) - (a.volume ?? 0))
    .slice(0, 15);
  if (businessFailures.length > 15) businessFailures = businessFailures.slice(0, 15);

  let technicalFailures = buildTopDeclinesByDescription(data.technicalFailures || [], getChannelCauseMap(data.reportType));
  if (technicalFailures.length > 15) technicalFailures = technicalFailures.slice(0, 15);

  let businessRows = businessFailures;
  if (businessRows.length > 15) businessRows = businessRows.slice(0, 15);
  let technicalRows = technicalFailures;
  if (technicalRows.length > 15) technicalRows = technicalRows.slice(0, 15);

  const periodLabel = derivePeriodLabel(data.startDateIso, data.endDateIso, data.dateRange);
  const totalTxnVol = Math.round(Number(data.totalTransactions ?? 0));
  const successVol = Math.round((Number(data.successRate ?? 0) / 100) * totalTxnVol);
  const failureVol = Math.max(0, totalTxnVol - successVol);

  const header = new Header({
    children: [
      new Paragraph({
        alignment: AlignmentType.CENTER,
        children: [
          new ImageRun({
            data: base64ToBytes(HEADER_IMAGE_BASE64),
            type: 'png',
            transformation: { width: 600, height: 101 }
          })
        ]
      })
    ]
  });

  const footer = new Footer({
    children: [
      new Paragraph({
        alignment: AlignmentType.CENTER,
        children: [
          new ImageRun({
            data: base64ToBytes(FOOTER_IMAGE_BASE64),
            type: 'png',
            transformation: { width: 450, height: 31 }
          })
        ]
      })
    ]
  });

  const children: Array<Paragraph | Table> = [
    new Paragraph({
      alignment: AlignmentType.CENTER,
      children: [
        new TextRun({
          text: `${data.reportType} ACQUIRING SERVICE - ANALYSIS`,
          bold: true,
          size: TITLE_SIZE,
          font: DEFAULT_FONT
        })
      ]
    }),
    new Paragraph({ text: '', spacing: { after: 200 } }),
    new Paragraph({
      heading: HeadingLevel.HEADING_2,
      children: [
        new TextRun({
          text: `${data.reportType} Analysis (${periodLabel})`,
          bold: true,
          size: HEADING_SIZE + 4,
          font: DEFAULT_FONT
        })
      ]
    }),
    new Paragraph({
      children: [
        new TextRun({
          text: `${data.reportType} Success and Failure Rate (${data.year})`,
          size: HEADING_SIZE,
          font: DEFAULT_FONT
        })
      ]
    }),
    new Paragraph({
      children: [
        new TextRun({
          text: periodLabel,
          size: HEADING_SIZE,
          font: DEFAULT_FONT
        })
      ]
    }),
    new Paragraph({ text: '', spacing: { after: 300 } }),
    new Table({
      width: { size: 100, type: WidthType.PERCENTAGE },
      rows: [
        new TableRow({
          children: [
            buildHeaderCell('Success Vol'),
            buildHeaderCell('% Success'),
            buildHeaderCell('Failure Vol'),
            buildHeaderCell('% Failure'),
            buildHeaderCell('Total Txn Vol')
          ]
        }),
        new TableRow({
          children: [
            buildCell(successVol.toString()),
            buildCell(`${data.successRate.toFixed(2)}%`),
            buildCell(failureVol.toString()),
            buildCell(`${data.failureRate.toFixed(2)}%`),
            buildCell(totalTxnVol.toString())
          ]
        })
      ]
    }),
    new Paragraph({ text: '', spacing: { after: 300 } }),
    new Paragraph({
      heading: HeadingLevel.HEADING_3,
      children: [new TextRun({ text: 'Top Business failure', bold: true, size: HEADING_SIZE + 2, font: DEFAULT_FONT })]
    }),
    new Table({
      width: { size: 100, type: WidthType.PERCENTAGE },
      rows: [
        new TableRow({ children: [buildHeaderCell('Description'), buildHeaderCell('Volume'), buildHeaderCell('Typical Cause')] }),
        ...businessRows.map((f) => new TableRow({ children: [buildCell(f.description || 'UNKNOWN'), buildCell(String(f.volume ?? 0)), buildCell(f.typicalCause || DEFAULT_TYPICAL_CAUSE)] }))
      ]
    }),
    new Paragraph({ text: '', spacing: { after: 300 } }),
    new Paragraph({
      heading: HeadingLevel.HEADING_3,
      children: [new TextRun({ text: 'Top Technical Decline', bold: true, size: HEADING_SIZE + 2, font: DEFAULT_FONT })]
    }),
    new Table({
      width: { size: 100, type: WidthType.PERCENTAGE },
      rows: [
        new TableRow({ children: [buildHeaderCell('Response Description'), buildHeaderCell('Volume'), buildHeaderCell('Typical Cause')] }),
        ...technicalRows.map((f) => new TableRow({ children: [buildCell(f.description || 'UNKNOWN'), buildCell(String(f.volume ?? 0)), buildCell(f.typicalCause || DEFAULT_TYPICAL_CAUSE)] }))
      ]
    })
  ];

  return new Document({
    styles: {
      default: {
        document: {
          run: {
            font: DEFAULT_FONT,
            size: DEFAULT_SIZE
          }
        }
      }
    },
    sections: [{ properties: {}, headers: { default: header }, footers: { default: footer }, children }]
  });
}

export async function generateCentralBankDocxBuffer(data: ReportData, _kpiReport?: KPIIntelligenceReport): Promise<Buffer> {
  const doc = buildCentralBankDocument(data);
  return Packer.toBuffer(doc);
}

export async function generateCentralBankDocxBlob(data: ReportData, _kpiReport?: KPIIntelligenceReport): Promise<Blob> {
  const doc = buildCentralBankDocument(data);
  return Packer.toBlob(doc);
}
